import{_ as t,o as a,c as l,a4 as r}from"./chunks/framework.DiadTcoQ.js";const u=JSON.parse('{"title":"Le genre et les articles","description":"","frontmatter":{},"headers":[],"relativePath":"module-1/gender-articles.md","filePath":"module-1/gender-articles.md"}'),i={name:"module-1/gender-articles.md"};function n(s,e,o,d,c,m){return a(),l("div",null,[...e[0]||(e[0]=[r('<h1 id="le-genre-et-les-articles" tabindex="-1">Le genre et les articles <a class="header-anchor" href="#le-genre-et-les-articles" aria-label="Permalink to “Le genre et les articles”">​</a></h1><p>En espagnol, chaque nom est masculin ou féminin. Il n&#39;existe pas de neutre. Les articles et les adjectifs s&#39;accordent toujours avec le nom.</p><h2 id="les-articles-definis" tabindex="-1">Les articles définis <a class="header-anchor" href="#les-articles-definis" aria-label="Permalink to “Les articles définis”">​</a></h2><table tabindex="0"><thead><tr><th></th><th>Singulier</th><th>Pluriel</th></tr></thead><tbody><tr><td>Masculin</td><td>el</td><td>los</td></tr><tr><td>Féminin</td><td>la</td><td>las</td></tr></tbody></table><p><em>el libro</em> — le livre · <em>los libros</em> — les livres <em>la casa</em> — la maison · <em>las casas</em> — les maisons</p><h2 id="les-articles-indefinis" tabindex="-1">Les articles indéfinis <a class="header-anchor" href="#les-articles-indefinis" aria-label="Permalink to “Les articles indéfinis”">​</a></h2><table tabindex="0"><thead><tr><th></th><th>Singulier</th><th>Pluriel</th></tr></thead><tbody><tr><td>Masculin</td><td>un</td><td>unos</td></tr><tr><td>Féminin</td><td>una</td><td>unas</td></tr></tbody></table><p><em>un perro</em> — un chien · <em>unas flores</em> — des fleurs</p><h2 id="reconnaitre-le-genre" tabindex="-1">Reconnaître le genre <a class="header-anchor" href="#reconnaitre-le-genre" aria-label="Permalink to “Reconnaître le genre”">​</a></h2><p><strong>Généralement masculins :</strong></p><ul><li>terminaison en <strong>-o</strong> : libro, vaso, perro</li><li>terminaison en <strong>-or</strong> : color, calor</li><li>jours, mois, langues, nombres</li></ul><p><strong>Généralement féminins :</strong></p><ul><li>terminaison en <strong>-a</strong> : casa, mesa, silla</li><li>terminaison en <strong>-ción / -sión</strong> : nación, televisión</li><li>terminaison en <strong>-dad / -tad</strong> : ciudad, libertad</li></ul><div class="warning custom-block"><p class="custom-block-title">Exceptions courantes</p><p>Certains mots en <strong>-a</strong> sont masculins : <em>el problema</em>, <em>el mapa</em>, <em>el día</em>, <em>el idioma</em>.</p></div><h2 id="le-pluriel" tabindex="-1">Le pluriel <a class="header-anchor" href="#le-pluriel" aria-label="Permalink to “Le pluriel”">​</a></h2><table tabindex="0"><thead><tr><th>Terminaison</th><th>Règle</th><th>Exemple</th></tr></thead><tbody><tr><td>Voyelle</td><td>+ s</td><td>casa → casas</td></tr><tr><td>Consonne</td><td>+ es</td><td>ciudad → ciudades</td></tr><tr><td>-z</td><td>-z → -ces</td><td>vez → veces</td></tr></tbody></table><h2 id="contraction-obligatoire" tabindex="-1">Contraction obligatoire <a class="header-anchor" href="#contraction-obligatoire" aria-label="Permalink to “Contraction obligatoire”">​</a></h2><p><strong>a + el = al</strong> · <strong>de + el = del</strong></p><p><em>Voy al mercado.</em> — Je vais au marché. <em>El coche del vecino.</em> — La voiture du voisin.</p><div class="tip custom-block"><p class="custom-block-title custom-block-title-default">TIP</p><p>La contraction ne s&#39;applique pas avec <strong>él</strong> (pronom) : <em>Hablo de él.</em> — Je parle de lui.</p></div>',20)])])}const p=t(i,[["render",n]]);export{u as __pageData,p as default};
